#include<bits/stdc++.h>
using namespace std;
int n,a[101][101],u[101][101];
int main(){
    cin>>n;
    for(int i=1;i<=n;i++){
        for(int j=1;j<=n;j++){
            cin>>a[i][j];
            int x=i,y=j;
            if(x>n/2) x=n-x+1;
            if(y>n/2) y=n-y+1;
            x=min(x,y);
            if(x%2) u[n-i+1][n-j+1]=a[i][j];
            else u[i][j]=a[i][j];
        }
    }
     for(int i=n;i>=1;i--){
        for(int j=1;j<=n;j++){
            cout<<u[j][i]<<" ";
        }
         cout<<"\n";
    }
    return 0;
}
